#include <stdio.h>
#include <stdlib.h>
#define MAX_N 100005
int n, m;
typedef struct Node {
    int val;
    struct Node* next;
} Node;
Node* adj[MAX_N];
void addEdge(int u, int v) {
    Node* newNode = (Node*) malloc(sizeof(Node));
    newNode->val = v;
    newNode->next = adj[u];
    adj[u] = newNode;
}
int distance(int u, int v) {
    int visited[MAX_N] = {0};
    int queue[MAX_N], front = 0, rear = 0;
    queue[rear++] = u;
    visited[u] = 1;
    int dist = 0;
    while (front < rear) {
        int size = rear - front;
        for (int i = 0; i < size; i++) {
            int node = queue[front++];
            if (node == v) return dist;
            Node* temp = adj[node];
            while (temp) {
                if (!visited[temp->val]) {
                    queue[rear++] = temp->val;
                    visited[temp->val] = 1;
                }
                temp = temp->next;
            }
        }
        dist++;
    }
    return -1;
}
int main() {
    scanf("%d", &n);
    for (int i = 0; i < n - 1; i++) {
        int u, v;
        scanf("%d %d", &u, &v);
        addEdge(u, v);
        addEdge(v, u);
    }
    scanf("%d", &m);
    for (int i = 0; i < m; i++) {
        int u, v;
        scanf("%d %d", &u, &v);
        printf("%d\n", distance(u, v));
    }
    return 0;
}

