#include <queue>
using namespace std;
const int MAX_N = 100005;
vector<int> adj[MAX_N];
int distance(int u, int v, vector<int> adj[]) {
    vector<bool> visited(MAX_N, false);
    queue<int> q;
    q.push(u);
    visited[u] = true;
    int dist = 0;
    while (!q.empty()) {
        int size = q.size();
        for (int i = 0; i < size; i++) {
            int node = q.front();
            q.pop();
            if (node == v) return dist;
            for (int neighbor : adj[node]) {
                if (!visited[neighbor]) {
                    q.push(neighbor);
                    visited[neighbor] = true;
                }
            }
        }
        dist++;
    }
    return -1;
}
